#include <bits/stdc++.h>
using namespace std;

const int N=55;

int n;
long long s[N],f[N];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%lld",&s[i]);
    for(int i=1;i<=n;i++)
        for(int j=49;j>=0;j--)
            if((s[i]>>j)&1){
                if(f[j])
                    s[i]^=f[j];
                else{
                    f[j]=s[i];
                    break;
                }
            }
    long long ans=0;
    for(int i=49;i>=0;i--)
        if(f[i] && !((ans>>i)&1))
            ans^=f[i];
    printf("%lld",ans);
    return 0;
}
